function solve(m: number, n: number, waitCost: number[][]): number {
    // Directions: right and down
    const dirs = [[0, 1], [1, 0]];

    // Dijkstra's algorithm
    const pq = new PriorityQueue<[number, number, number, number]>([0, 0, 0, 0]); // [cost, row, col, time]
    const dist = Array(m).fill(0).map(() => Array(n).fill(Infinity));
    dist[0][0] = 1; // Initial cost is the entrance cost of (0, 0)

    while (!pq.isEmpty()) {
        const [cost, row, col, time] = pq.poll();

        // If we reached the destination
        if (row === m - 1 && col === n - 1) {
            return cost;
        }

        // If current cost is higher than recorded, skip
        if (cost > dist[row][col]) {
            continue;
        }

        // Check if current time is odd (move) or even (wait)
        if (time % 2 === 1) {
            // Odd time: must move right or down
            for (const [dr, dc] of dirs) {
                const newRow = row + dr;
                const newCol = col + dc;

                // Check if new position is valid
                if (newRow >= 0 && newRow < m && newCol >= 0 && newCol < n) {
                    const newTime = time + 1;
                    const newCost = cost + (newRow + 1) * (newCol + 1);

                    if (newCost < dist[newRow][newCol]) {
                        dist[newRow][newCol] = newCost;
                        pq.add([newCost, newRow, newCol, newTime]);
                    }
                }
            }
        } else {
            // Even time: must wait
            const newTime = time + 1;
            const newCost = cost + waitCost[row][col];

            if (newCost < dist[row][col]) {
                dist[row][col] = newCost;
                pq.add([newCost, row, col, newTime]);
            }
        }
    }

    // If no path found (should not happen as grid is connected)
    return -1;
}

class PriorityQueue<T> {
    private heap: T[];
    private comparator: (a: T, b: T) => number;

    constructor(private initialHeap: T[]) {
        this.heap = initialHeap;
        this.comparator = (a, b) => {
            // Custom comparator for priority queue
            return a[0] - b[0];
        };
        this.buildHeap();
    }

    private buildHeap(): void {
        for (let i = Math.floor(this.heap.length / 2) - 1; i >= 0; i--) {
            this.heapify(i);
        }
    }

    private heapify(i: number): void {
        let smallest = i;
        const left = 2 * i + 1;
        const right = 2 * i + 2;

        if (left < this.heap.length && this.comparator(this.heap[left], this.heap[smallest]) < 0) {
            smallest = left;
        }

        if (right < this.heap.length && this.comparator(this.heap[right], this.heap[smallest]) < 0) {
            smallest = right;
        }

        if (smallest !== i) {
            [this.heap[i], this.heap[smallest]] = [this.heap[smallest], this.heap[i]];
            this.heapify(smallest);
        }
    }

    public poll(): T {
        if (this.heap.length === 0) return undefined as any;
        const result = this.heap[0];
        this.heap[0] = this.heap[this.heap.length - 1];
        this.heap.pop();
        this.heapify(0);
        return result;
    }

    public add(item: T): void {
        this.heap.push(item);
        this.heapify(this.heap.length - 1);
    }

    public isEmpty(): boolean {
        return this.heap.length === 0;
    }
}

